import React, { useState, useRef, useEffect, useCallback } from "react";

const subjectsByBranch = {
  CSE: ["Data Structures", "Algorithms", "Operating Systems", "DBMS", "Computer Networks"],
  ECE: ["Signals & Systems", "Digital Electronics", "Microprocessors", "VLSI", "Communication Systems"],
  EEE: ["Circuit Theory", "Electrical Machines", "Power Systems", "Control Systems", "Power Electronics"],
  ME:  ["Thermodynamics", "Fluid Mechanics", "Manufacturing", "Machine Design", "Heat Transfer"],
  IT:  ["Web Technologies", "Software Engineering", "Cloud Computing", "AI & ML", "Cyber Security"],
};

function Attendance() {
  const videoRef = useRef(null);
  const streamRef = useRef(null);
  const [step, setStep] = useState("idle");
  const [selectedSubject, setSelectedSubject] = useState("");
  const [message, setMessage] = useState("");
  const [attendanceLog, setAttendanceLog] = useState([]);
  const [progress, setProgress] = useState(0);
  const [cameraReady, setCameraReady] = useState(false);
  const [countdown, setCountdown] = useState(3);

  const student = JSON.parse(localStorage.getItem("student")) || { name: "Student", id: "N/A", branch: "CSE" };
  const subjects = subjectsByBranch[student.branch] || subjectsByBranch["CSE"];

  useEffect(() => {
    fetchAttendance();
    return () => stopCamera();
  }, []);

  const fetchAttendance = async () => {
    try {
      const res = await fetch("http://localhost:5000/attendance/" + student.id);
      const data = await res.json();
      setAttendanceLog(data);
    } catch (err) {}
  };

  const stopCamera = () => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach((t) => t.stop());
      streamRef.current = null;
    }
    setCameraReady(false);
  };

  const handleSubjectSelect = () => {
    if (!selectedSubject) { alert("Please select a subject first!"); return; }
    const today = new Date().toLocaleDateString("en-IN");
    const alreadyMarked = attendanceLog.some(
      (r) => r.date === today && r.studentId === student.id && r.subject === selectedSubject
    );
    if (alreadyMarked) { alert(`Attendance for "${selectedSubject}" already marked today!`); return; }
    setStep("scanning");
    startCamera();
  };

  const startCamera = async () => {
    setCameraReady(false);
    setCountdown(3);
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: "user" } });
      streamRef.current = mediaStream;
      if (videoRef.current) {
        videoRef.current.srcObject = mediaStream;
        videoRef.current.onloadedmetadata = () => {
          videoRef.current.play();
          // Countdown before allowing scan
          let count = 3;
          setCountdown(count);
          setMessage("⏳ Position your eye in the circle... scanning in 3s");
          const timer = setInterval(() => {
            count--;
            setCountdown(count);
            setMessage(`⏳ Position your eye in the circle... scanning in ${count}s`);
            if (count <= 0) {
              clearInterval(timer);
              setCameraReady(true);
              setMessage("👁️ Eye detected! Click 'Capture & Scan Iris' now");
            }
          }, 1000);
        };
      }
    } catch (err) {
      setStep("error");
      setMessage("❌ Camera error: " + err.message);
    }
  };

  const scanIris = () => {
    if (!cameraReady) {
      alert("Please wait for the camera to detect your eye first!");
      return;
    }
    setStep("processing");
    setProgress(0);
    let prog = 0;
    const interval = setInterval(() => {
      prog += 8;
      setProgress(prog);
      if (prog === 24) setMessage("🔍 Scanning iris pattern...");
      if (prog === 48) setMessage("🔍 Detecting unique eye structure...");
      if (prog === 72) setMessage("🔍 Matching iris with database...");
      if (prog === 88) setMessage("✅ Iris matched! Recording attendance...");
      if (prog >= 100) {
        clearInterval(interval);
        markAttendance();
      }
    }, 250);
  };

  const markAttendance = async () => {
    stopCamera();
    const now = new Date();
    const record = {
      studentId: student.id,
      studentName: student.name,
      subject: selectedSubject,
      date: now.toLocaleDateString("en-IN"),
      time: now.toLocaleTimeString("en-IN"),
      status: "Present",
      method: "Iris Scan",
    };
    try {
      await fetch("http://localhost:5000/attendance", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(record),
      });
    } catch (err) {}
    setStep("done");
    setMessage(`✅ Attendance for "${selectedSubject}" marked successfully!`);
    setAttendanceLog((prev) => [record, ...prev]);
  };

  const reset = () => {
    stopCamera();
    setStep("idle");
    setSelectedSubject("");
    setMessage("");
    setProgress(0);
    setCameraReady(false);
  };

  const today = new Date().toLocaleDateString("en-IN");

  return (
    <div className="content">
      <h3>👁️ Iris Scan Attendance</h3>
      <p style={{ color: "#555", marginTop: "5px" }}>
        Student: <strong>{student.name}</strong> | ID: <strong>{student.id}</strong> | Branch: <strong>{student.branch}</strong>
      </p>

      {/* STEP 1 — Select Subject */}
      {step === "idle" && (
        <div style={{ marginTop: "25px" }}>
          <h4 style={{ marginBottom: "15px" }}>📚 Select Subject to Mark Attendance</h4>
          <div style={styles.subjectGrid}>
            {subjects.map((sub, i) => {
              const marked = attendanceLog.some(
                (r) => r.date === today && r.subject === sub && r.studentId === student.id
              );
              return (
                <div
                  key={i}
                  style={{
                    ...styles.subjectCard,
                    background: marked ? "#d4edda" : selectedSubject === sub ? "#007bff" : "white",
                    color: marked ? "#155724" : selectedSubject === sub ? "white" : "#333",
                    border: marked ? "2px solid #28a745" : selectedSubject === sub ? "2px solid #0056b3" : "2px solid #ddd",
                    cursor: marked ? "default" : "pointer",
                  }}
                  onClick={() => !marked && setSelectedSubject(sub)}
                >
                  <span style={{ fontSize: "24px" }}>{marked ? "✅" : "📖"}</span>
                  <span style={{ fontSize: "12px", marginTop: "6px", textAlign: "center", fontWeight: "500" }}>{sub}</span>
                  {marked && <span style={{ fontSize: "11px", color: "#28a745", fontWeight: "bold" }}>Marked ✓</span>}
                </div>
              );
            })}
          </div>

          {selectedSubject && (
            <div style={{ marginTop: "20px", textAlign: "center" }}>
              <p style={{ marginBottom: "12px", fontWeight: "bold", color: "#007bff", fontSize: "16px" }}>
                📌 Selected: {selectedSubject}
              </p>
              <button style={styles.scanBtn} onClick={handleSubjectSelect}>
                📷 Open Camera & Scan Iris
              </button>
            </div>
          )}
        </div>
      )}

      {/* STEP 2 — Camera */}
      {step === "scanning" && (
        <div style={{ marginTop: "20px", textAlign: "center" }}>
          <p style={{ fontWeight: "bold", color: "#333", marginBottom: "10px", fontSize: "15px" }}>
            📚 Marking attendance for: <span style={{ color: "#007bff" }}>{selectedSubject}</span>
          </p>
          <div style={styles.cameraWrapper}>
            <video ref={videoRef} autoPlay playsInline muted style={styles.video} />
            {/* Iris overlay ring */}
            <div style={styles.irisOverlay}>
              <div style={{
                ...styles.irisRing,
                borderColor: cameraReady ? "#00ff88" : "#ffcc00",
                boxShadow: cameraReady ? "0 0 25px rgba(0,255,136,0.7)" : "0 0 20px rgba(255,204,0,0.5)",
              }} />
              <div style={{
                ...styles.irisRingInner,
                borderColor: cameraReady ? "#00ff88" : "#ffcc00",
              }} />
              {/* Countdown */}
              {!cameraReady && (
                <div style={styles.countdown}>{countdown}</div>
              )}
              {/* Ready indicator */}
              {cameraReady && (
                <div style={styles.readyDot}>●</div>
              )}
            </div>
          </div>

          <p style={{ marginTop: "12px", fontWeight: "bold", color: cameraReady ? "#28a745" : "#e67e00" }}>
            {message}
          </p>

          <div style={{ marginTop: "15px" }}>
            <button
              style={{ ...styles.scanBtn, opacity: cameraReady ? 1 : 0.5 }}
              onClick={scanIris}
              disabled={!cameraReady}
            >
              👁️ Capture & Scan Iris
            </button>
            <button style={styles.cancelBtn} onClick={reset}>Cancel</button>
          </div>
          {!cameraReady && (
            <p style={{ marginTop: "8px", fontSize: "13px", color: "#888" }}>
              ⚠️ Button will activate once your eye is positioned in the circle
            </p>
          )}
        </div>
      )}

      {/* STEP 3 — Processing */}
      {step === "processing" && (
        <div style={{ marginTop: "30px", textAlign: "center" }}>
          <div style={{ fontSize: "60px", marginBottom: "15px" }}>🔍</div>
          <div style={styles.progressBar}>
            <div style={{ ...styles.progressFill, width: progress + "%" }} />
          </div>
          <p style={{ marginTop: "5px", fontSize: "13px", color: "#888" }}>{progress}%</p>
          <p style={{ marginTop: "10px", fontWeight: "bold", color: "#007bff", fontSize: "15px" }}>{message}</p>
        </div>
      )}

      {/* STEP 4 — Done */}
      {step === "done" && (
        <div style={{ marginTop: "30px", textAlign: "center" }}>
          <div style={{ fontSize: "70px", marginBottom: "10px" }}>✅</div>
          <div style={styles.successBox}>{message}</div>
          <button style={styles.scanBtn} onClick={reset}>📚 Mark Another Subject</button>
        </div>
      )}

      {/* Error */}
      {step === "error" && (
        <div style={{ marginTop: "20px", textAlign: "center" }}>
          <div style={styles.errorBox}>{message}</div>
          <button style={styles.scanBtn} onClick={reset}>Try Again</button>
        </div>
      )}

      {/* Attendance Log */}
      <div style={{ marginTop: "35px" }}>
        <h4>📋 Today's Attendance — {today}</h4>
        {attendanceLog.filter(r => r.date === today).length === 0 ? (
          <p style={{ color: "#888", marginTop: "10px" }}>No attendance marked today yet.</p>
        ) : (
          <table className="timetable" style={{ marginTop: "10px" }}>
            <thead>
              <tr><th>Subject</th><th>Time</th><th>Status</th><th>Method</th></tr>
            </thead>
            <tbody>
              {attendanceLog.filter(r => r.date === today).map((r, i) => (
                <tr key={i}>
                  <td><strong>{r.subject}</strong></td>
                  <td>{r.time}</td>
                  <td style={{ color: "green", fontWeight: "bold" }}>✅ {r.status}</td>
                  <td>{r.method}</td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>

      <style>{`
        @keyframes pulse {
          0% { transform: translate(-50%, -50%) scale(1); opacity: 1; }
          50% { transform: translate(-50%, -50%) scale(1.08); opacity: 0.7; }
          100% { transform: translate(-50%, -50%) scale(1); opacity: 1; }
        }
      `}</style>
    </div>
  );
}

const styles = {
  subjectGrid: { display: "flex", flexWrap: "wrap", gap: "12px", marginTop: "10px" },
  subjectCard: {
    display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center",
    width: "130px", height: "95px", borderRadius: "10px", padding: "10px",
    transition: "all 0.2s", boxShadow: "0 2px 6px rgba(0,0,0,0.1)",
  },
  scanBtn: {
    padding: "12px 28px", background: "#007bff", color: "white",
    border: "none", borderRadius: "8px", fontSize: "15px", cursor: "pointer", margin: "5px",
  },
  cancelBtn: {
    padding: "12px 28px", background: "#dc3545", color: "white",
    border: "none", borderRadius: "8px", fontSize: "15px", cursor: "pointer", margin: "5px",
  },
  cameraWrapper: {
    position: "relative", display: "inline-block",
    borderRadius: "12px", overflow: "hidden", border: "3px solid #007bff",
  },
  video: { width: "340px", height: "260px", objectFit: "cover", display: "block" },
  irisOverlay: { position: "absolute", top: 0, left: 0, right: 0, bottom: 0, pointerEvents: "none" },
  irisRing: {
    position: "absolute", top: "50%", left: "50%",
    width: "140px", height: "140px", borderRadius: "50%",
    border: "3px solid #00ff88", transform: "translate(-50%, -50%)",
    animation: "pulse 1.5s infinite",
  },
  irisRingInner: {
    position: "absolute", top: "50%", left: "50%",
    width: "55px", height: "55px", borderRadius: "50%",
    border: "2px solid #00ff88", transform: "translate(-50%, -50%)",
  },
  countdown: {
    position: "absolute", top: "50%", left: "50%",
    transform: "translate(-50%, -50%)",
    fontSize: "36px", fontWeight: "bold", color: "#ffcc00",
  },
  readyDot: {
    position: "absolute", top: "50%", left: "50%",
    transform: "translate(-50%, -50%)",
    fontSize: "20px", color: "#00ff88",
  },
  progressBar: {
    width: "340px", height: "14px", background: "#e0e0e0",
    borderRadius: "7px", margin: "10px auto", overflow: "hidden",
  },
  progressFill: {
    height: "100%", background: "linear-gradient(90deg, #007bff, #00ff88)",
    borderRadius: "7px", transition: "width 0.25s ease",
  },
  successBox: {
    background: "#d4edda", color: "#155724", padding: "15px 20px",
    borderRadius: "8px", marginBottom: "15px", fontWeight: "bold", fontSize: "15px",
  },
  errorBox: {
    background: "#f8d7da", color: "#721c24", padding: "15px 20px",
    borderRadius: "8px", marginBottom: "15px", fontWeight: "bold",
  },
};

export default Attendance;
